import request from '@/plugins/request';
// 理论考试大屏
export function getPracticalexamination() {
    return request({
        url: '/exam/screen/practicalWaitingRoom',
        method: 'get'
    })
}
// 实操考试大屏
export function getTheoryexamination(id) {
    return request({
        url: '/exam/screen/practical/room',
        method: 'get',
        params: {
            examRoom: id
        }
    })
}

// 实操大屏考试排队叫号
export function getTheoryexaminationQueue() {
    return request({
        url: '/exam/screen/practicalWaitingRoom',
        method: 'get'
    })
}
