<template>
 <header class="screen-top">
  <div class="top-logo">
   <img src="@/assets/images/screen/title.png" alt="天津市家政服务业协会" />
  </div>

  <h1 class="top-title">{{ title }}</h1>
  <div class="top-time">
   <div class="date-wrap">
    <p>{{ currentDate }}</p>
    <p>{{ currentWeek }}</p>
   </div>
   <p class="clock">{{ currentTime }}</p>
  </div>
 </header>
</template>

<script>
 export default {
  name: "ScreenHeader",
  props: {
   title: {
    type: String,
    default: "",
   },
  },
  data() {
   return {
    currentDate: "",
    currentWeek: "",
    currentTime: "",
    timer: null,
   };
  },
  methods: {
   updateNow() {
    const now = new Date();
    const weekList = [
     "星期日",
     "星期一",
     "星期二",
     "星期三",
     "星期四",
     "星期五",
     "星期六",
    ];

    const pad = (v) => String(v).padStart(2, "0");

    this.currentDate = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(
     now.getDate(),
    )}`;

    this.currentWeek = weekList[now.getDay()];

    this.currentTime = `${pad(now.getHours())}:${pad(now.getMinutes())}:${pad(
     now.getSeconds(),
    )}`;
   },
  },
  mounted() {
   this.updateNow();
   this.timer = setInterval(this.updateNow, 1000);
  },
  beforeDestroy() {
   if (this.timer) clearInterval(this.timer);
  },
 };
</script>

<style lang="scss" scoped>
 .screen-top {
  padding: 0 40px;
  position: relative;
  height: 96px;
  display: flex;
  align-items: center;
  justify-content: space-between;
 }

 .top-logo {
  z-index: 1;
  width: 300px;
  min-width: 300px;
  height: 46px;
  display: flex;
  align-items: center;

  img {
   width: 100%;
   height: 100%;
   object-fit: contain;
  }
 }

 .top-title {
  z-index: 1;
  font-weight: 700;
  font-size: 74px;
  color: #ffffff;
 }

 .top-time {
  z-index: 1;
  min-width: 290px;
  display: flex;
  align-items: center;
  // justify-content: flex-end;
  color: #fff;
 }

 .date-wrap {
  margin-right: 16px;
  text-align: right;
  font-size: 26px;

  p {
   margin: 0;
   line-height: 1.3;
  }
 }

 .clock {
  font-size: 36px;
  margin: 0;
  line-height: 1;
 }
</style>
